212	            } else {
213	                vec!["private".to_string()]
214	            };
215	
216	            results.push(Symbol {
217	                id: id.to_string(),
218	                name,
219	                kind,
220	                location,
221	                signature: None,
222	                doc_comment: None,
223	                parent_id,
224	                modifiers,
225	                is_exported,
226	                complexity: None,
227	            });
228	        }
229	
230	        results
231	    }
232	
233	    fn extract_calls(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<CallSite> {
234	        let queries = load_rust_queries();
235	        let file_path_str = file_path.to_string_lossy().to_string();
236	        let mut results = Vec::new();
237	
238	        let query = match Query::new(&tree_sitter_rust::LANGUAGE.into(), &queries.calls) {
239	            Ok(q) => q,
240	            Err(_) => return results,
241	        };
242	
243	        let mut cursor = QueryCursor::new();
244	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
245	
246	        while let Some(m) = matches.next() {
247	            let mut callee_name = String::new();
248	            let mut call_type = CallType::Direct;
249	            let mut location = SourceLocation {
250	                file_path: file_path_str.clone(),
251	                line: 0,
252	                column: 0,
253	                end_line: 0,
254	                end_column: 0,
255	            };
256	
257	            for capture in m.captures {
258	                let node = capture.node;
259	                let capture_name = query.capture_names()[capture.index as usize];
260	
261	                match capture_name {
262	                    "call.name" => {
263	                        callee_name = self.node_text(node, source).to_string();
264	                    }
265	                    "call" => {
266	                        location = self.node_to_location(node);
267	                    }
268	                    "call.method" => {
269	                        call_type = CallType::Virtual; // Rust 方法调用可能通过 trait 动态分发
270	                        location = self.node_to_location(node);
271	                    }
272	                    "call.macro" => {
273	                        call_type = CallType::MacroExpansion;
274	                        location = self.node_to_location(node);
275	                    }
276	                    _ => {}
277	                }
278	            }
279	
280	            if !callee_name.is_empty() && location.line > 0 {
281	                results.push(CallSite {
282	                    caller_id: String::new(), // 由外部调用者上下文补充
283	                    callee_name,
284	                    location,
285	                    call_type,
286	                    confidence: 0.9,
287	                });
288	            }
289	        }
290	
291	        results
292	    }
293	
294	    fn extract_imports(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Import> {
295	        let queries = load_rust_queries();
296	        let file_path_str = file_path.to_string_lossy().to_string();
297	        let mut results = Vec::new();
298	
299	        let query = match Query::new(&tree_sitter_rust::LANGUAGE.into(), &queries.imports) {
300	            Ok(q) => q,
301	            Err(_) => return results,
302	        };
303	
304	        let mut cursor = QueryCursor::new();
305	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
306	
307	        while let Some(m) = matches.next() {
308	            let mut import_path = String::new();
309	            let mut alias = None;
310	            let mut import_line: u64 = 0;
311	
312	            for capture in m.captures {
313	                let node = capture.node;
314	                let capture_name = query.capture_names()[capture.index as usize];
315	
316	                match capture_name {
317	                    "import.path" => {
318	                        import_path = self.node_text(node, source).to_string();
319	                    }
320	                    "import.name" => {
321	                        alias = Some(self.node_text(node, source).to_string());
322	                    }
323	                    "import" | "import.extern" => {
324	                        import_line = node.start_position().row as u64 + 1;
325	                    }
326	                    _ => {}
327	                }
328	            }
329	
330	            // 对于 extern crate（仅 alias 无 import_path），使用 alias 作为路径
331	            let path = if import_path.is_empty() {
332	                alias.clone().unwrap_or_default()
333	            } else {
334	                import_path
335	            };
336	
337	            if !path.is_empty() {
338	                results.push(Import {
339	                    file_path: file_path_str.clone(),
340	                    import_path: path,
341	                    alias,
342	                    line: import_line,
343	                    resolution: ImportResolution::Unresolved,
344	                });
345	            }
346	        }
347	
348	        results
349	    }
