/// 单个文件的索引统计（内部用）
#[derive(Debug, Clone, Default)]
struct FileIndexStats {
    symbols: u64,
    calls: u64,
    imports: u64,
}

impl FileIndexStats {
    /// 合并多个文件的统计数据
    fn merge(stats: &[Self]) -> Self {
        let mut merged = Self::default();
        for s in stats {
            merged.symbols += s.symbols;
            merged.calls += s.calls;
            merged.imports += s.imports;
        }
        merged
    }
}

