1	//! TypeScript 语言解析器
2	//!
3	//! 使用 tree-sitter-typescript grammar 解析 .ts/.tsx 文件，
4	//! 提取函数、类、接口、方法等符号定义，
5	//! 以及函数调用和 import 导入语句。
6	
7	use std::path::Path;
8	use std::sync::Mutex;
9	
10	use codeconnect_core::error::CodeConnectError;
11	use codeconnect_core::symbol_id::StableSymbolId;
12	use codeconnect_core::types::{
13	    CallSite, CallType, Import, ImportResolution, SourceLocation, Symbol, SymbolKind,
14	};
15	use streaming_iterator::StreamingIterator;
16	use tree_sitter::{Parser, Query, QueryCursor, Tree};
17	
18	use crate::query_loader::load_typescript_queries;
19	use crate::r#trait::LanguageParser;
20	
21	/// TypeScript 语言解析器
22	///
23	/// 包装了 tree-sitter-typescript grammar 和一个 `Mutex<Parser>`，
24	/// 确保并发调用时的线程安全。
25	pub struct TypeScriptParser {
26	    /// tree-sitter 解析器实例（Mutex 因为 Parser 不是 Sync）
27	    parser: Mutex<Parser>,
28	    /// TS language 对象（用于 Query::new 编译查询）
29	    language: tree_sitter::Language,
30	}
31	
32	impl TypeScriptParser {
33	    /// 创建新的 TypeScript 解析器
34	    pub fn new() -> Self {
35	        let mut parser = Parser::new();
36	        let language: tree_sitter::Language = tree_sitter_typescript::LANGUAGE_TYPESCRIPT.into();
37	        parser
38	            .set_language(&language)
39	            .expect("加载 TypeScript tree-sitter grammar 失败");
40	        Self {
41	            parser: Mutex::new(parser),
42	            language,
43	        }
44	    }
45	
46	    /// 将 tree-sitter 节点转为源码位置（0-based → 1-based）
47	    fn node_to_location(&self, node: tree_sitter::Node, file_path: &str) -> SourceLocation {
48	        let start = node.start_position();
49	        let end = node.end_position();
50	        SourceLocation {
51	            file_path: file_path.to_string(),
52	            line: start.row as u64 + 1,
53	            column: start.column as u64 + 1,
54	            end_line: end.row as u64 + 1,
55	            end_column: end.column as u64 + 1,
56	        }
57	    }
58	
59	    /// 获取节点的源码文本（UTF-8 安全）
60	    fn node_text<'a>(&self, node: tree_sitter::Node, source: &'a str) -> &'a str {
61	        node.utf8_text(source.as_bytes()).unwrap_or("")
62	    }
63	}
64	
65	impl Default for TypeScriptParser {
66	    fn default() -> Self {
67	        Self::new()
68	    }
69	}
70	
71	impl LanguageParser for TypeScriptParser {
72	    fn language(&self) -> &'static str {
73	        "typescript"
74	    }
75	
76	    fn file_extensions(&self) -> &[&str] {
77	        &["ts", "tsx"]
78	    }
79	
80	    fn parse(&self, source: &str) -> Result<Tree, CodeConnectError> {
81	        let mut parser = self.parser.lock().map_err(|e| CodeConnectError::Parse {
82	            file: Path::new("").to_path_buf(),
83	            message: format!("获取解析器锁失败: {}", e),
84	        })?;
85	        parser
86	            .parse(source, None)
87	            .ok_or_else(|| CodeConnectError::Parse {
88	                file: Path::new("").to_path_buf(),
89	                message: "TypeScript 源码解析失败，可能包含语法错误".to_string(),
90	            })
91	    }
92	
93	    fn extract_symbols(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Symbol> {
94	        let queries = load_typescript_queries();
95	        let file_path_str = file_path.to_string_lossy().to_string();
96	        let mut results = Vec::new();
97	        // 用 HashSet 去重——同一个符号可能被多个 query pattern 匹配
98	        let mut seen_names: std::collections::HashSet<(String, String)> =
99	            std::collections::HashSet::new();
100	
101	        let query = match Query::new(&self.language, &queries.symbols) {
102	            Ok(q) => q,
103	            Err(_) => return results,
104	        };
105	
106	        let mut cursor = QueryCursor::new();
107	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
108	
109	        while let Some(m) = matches.next() {
110	            let mut name = String::new();
111	            let mut kind = SymbolKind::Unknown("unknown".to_string());
112	            let mut location = self.node_to_location(tree.root_node(), &file_path_str);
113	            let mut is_exported = false;
114	
115	            for capture in m.captures {
116	                let node = capture.node;
117	                let capture_name = query.capture_names()[capture.index as usize];
118	
119	                match capture_name {
120	                    "symbol.name" => {
121	                        name = self.node_text(node, source).to_string();
122	                    }
123	                    "symbol.function" => {
124	                        kind = SymbolKind::Function;
125	                        location = self.node_to_location(node, &file_path_str);
126	                    }
127	                    "symbol.method" => {
128	                        kind = SymbolKind::Method;
129	                        location = self.node_to_location(node, &file_path_str);
130	                    }
131	                    "symbol.class" => {
132	                        kind = SymbolKind::Class;
133	                        location = self.node_to_location(node, &file_path_str);
134	                    }
135	                    "symbol.interface" => {
136	                        kind = SymbolKind::Interface;
137	                        location = self.node_to_location(node, &file_path_str);
138	                    }
139	                    "symbol.enum" => {
140	                        kind = SymbolKind::Enum;
141	                        location = self.node_to_location(node, &file_path_str);
142	                    }
143	                    "symbol.type_alias" => {
144	                        kind = SymbolKind::TypeAlias;
145	                        location = self.node_to_location(node, &file_path_str);
146	                    }
147	                    "symbol.variable" => {
148	                        kind = SymbolKind::Variable;
149	                        location = self.node_to_location(node, &file_path_str);
150	                    }
151	                    "symbol.exported" => {
152	                        is_exported = true;
153	                    }
154	                    _ => {}
155	                }
156	            }
157	
158	            if name.is_empty() {
159	                continue;
160	            }
161	
162	            // 去重：同一文件中同名同类型的符号只保留一个
163	            let kind_str = kind_to_str(&kind);
164	            let dedup_key = (name.clone(), kind_str.to_string());
165	            if seen_names.contains(&dedup_key) {
166	                continue;
167	            }
168	            seen_names.insert(dedup_key);
169	
170	            let id = StableSymbolId::new("typescript", &file_path_str, kind_str, &name);
171	
172	            // TS 中 export 关键字标记的符号为公开 API
173	            let modifiers = if is_exported {
174	                vec!["export".to_string()]
175	            } else {
176	                vec![]
177	            };
178	
179	            results.push(Symbol {
180	                id: id.to_string(),
181	                name,
182	                kind,
183	                location,
184	                signature: None,
185	                doc_comment: None,
186	                parent_id: None,
187	                modifiers,
188	                is_exported,
189	                complexity: None,
190	            });
191	        }
192	
193	        results
194	    }
195	
196	    fn extract_calls(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<CallSite> {
197	        let queries = load_typescript_queries();
198	        let file_path_str = file_path.to_string_lossy().to_string();
199	        let mut results = Vec::new();
200	
201	        let query = match Query::new(&self.language, &queries.calls) {
202	            Ok(q) => q,
203	            Err(_) => return results,
204	        };
205	
206	        let mut cursor = QueryCursor::new();
207	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
208	
209	        while let Some(m) = matches.next() {
210	            let mut callee_name = String::new();
211	            let mut call_type = CallType::Direct;
212	            let mut location = SourceLocation {
213	                file_path: file_path_str.clone(),
214	                line: 0,
215	                column: 0,
216	                end_line: 0,
217	                end_column: 0,
218	            };
219	
220	            for capture in m.captures {
221	                let node = capture.node;
222	                let capture_name = query.capture_names()[capture.index as usize];
223	
224	                match capture_name {
225	                    "call.name" => {
226	                        callee_name = self.node_text(node, source).to_string();
227	                    }
228	                    "call" => {
229	                        location = self.node_to_location(node, &file_path_str);
230	                    }
231	                    "call.method" => {
232	                        call_type = CallType::Virtual;
233	                        location = self.node_to_location(node, &file_path_str);
234	                    }
235	                    "call.constructor" => {
236	                        call_type = CallType::Direct;
237	                        location = self.node_to_location(node, &file_path_str);
238	                    }
239	                    _ => {}
240	                }
241	            }
242	
243	            if !callee_name.is_empty() && location.line > 0 {
244	                results.push(CallSite {
245	                    caller_id: String::new(),
246	                    callee_name,
247	                    location,
248	                    call_type,
249	                    confidence: 0.9,
250	                });
251	            }
252	        }
253	
254	        results
255	    }
256	
257	    fn extract_imports(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<Import> {
258	        let queries = load_typescript_queries();
259	        let file_path_str = file_path.to_string_lossy().to_string();
260	        let mut results = Vec::new();
261	
262	        let query = match Query::new(&self.language, &queries.imports) {
263	            Ok(q) => q,
264	            Err(_) => return results,
265	        };
266	
267	        let mut cursor = QueryCursor::new();
268	        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
269	
270	        while let Some(m) = matches.next() {
271	            let mut import_path = String::new();
272	            let mut alias = None;
273	            let mut match_line: u64 = 0;
274	
275	            for capture in m.captures {
276	                let node = capture.node;
277	                let capture_name = query.capture_names()[capture.index as usize];
278	
279	                match capture_name {
280	                    "import.path" => {
281	                        import_path = self.node_text(node, source).to_string();
282	                    }
283	                    "import.name" => {
284	                        alias = Some(self.node_text(node, source).to_string());
285	                    }
286	                    "import.default" => {
287	                        alias = Some(self.node_text(node, source).to_string());
288	                    }
289	                    _ => {
290	                        if match_line == 0 {
291	                            match_line = node.start_position().row as u64 + 1;
292	                        }
293	                    }
294	                }
295	            }
296	
297	            if !import_path.is_empty() {
298	                results.push(Import {
299	                    file_path: file_path_str.clone(),
300	                    import_path,
301	                    alias,
302	                    line: match_line,
303	                    resolution: ImportResolution::Unresolved,
304	                });
305	            }
306	        }
307	
308	        results
309	    }
310	
311	    fn infer_package(&self, file_path: &Path, _source: &str) -> Option<String> {
312	        // TS 项目：从文件路径推断包名——取 src 目录的父目录名
313	        let mut current = file_path.parent();
314	        while let Some(dir) = current {
315	            if let Some(name) = dir.file_name().and_then(|n| n.to_str()) {
316	                if name == "src" {
317	                    current = dir.parent();
318	                    continue;
319	                }
320	                if !name.is_empty() {
321	                    return Some(name.to_string());
322	                }
323	            }
324	            current = dir.parent();
325	        }
326	        None
327	    }
328	}
329	
330	/// 辅助函数：将 SymbolKind 转为字符串
331	fn kind_to_str(kind: &SymbolKind) -> &str {
332	    match kind {
333	        SymbolKind::Function => "function",
334	        SymbolKind::Method => "method",
335	        SymbolKind::Class => "class",
336	        SymbolKind::Interface => "interface",
337	        SymbolKind::Enum => "enum",
338	        SymbolKind::TypeAlias => "type_alias",
339	        SymbolKind::Variable => "variable",
340	        _ => "unknown",
341	    }
342	}
343	
344	#[cfg(test)]
345	mod tests {
346	    use super::*;
347	    use std::path::PathBuf;
348	
349	    fn parse_source(source: &str) -> (Tree, TypeScriptParser) {
350	        let parser = TypeScriptParser::new();
351	        let tree = parser.parse(source).expect("解析测试源码失败");
352	        (tree, parser)
353	    }
354	
355	    #[test]
356	    fn test_parse_function() {
357	        let source = r#"
358	function greet(name: string): string {
359	    return `Hello, ${name}`;
360	}
361	"#;
362	        let (tree, parser) = parse_source(source);
363	        let symbols = parser.extract_symbols(&tree, source, Path::new("test.ts"));
364	        let func = symbols.iter().find(|s| s.name == "greet");
365	        assert!(func.is_some(), "应找到 greet 函数");
366	        assert_eq!(func.unwrap().kind, SymbolKind::Function);
367	    }
368	
369	    #[test]
370	    fn test_parse_class() {
