fn kind_priority_val(kind: &SymbolKind) -> u32 {
    match kind {
        SymbolKind::Function => 10,
        SymbolKind::Method => 9,
        SymbolKind::Class => 8,
        SymbolKind::Variable => 1,
        _ => 0,
    }
}

