    /// 调试测试：dump import 语句的 AST 结构
    #[test]
    fn debug_import_ast() {
        let source = r#"
import { AuthService } from "./auth";
"#;
        let parser = JavaScriptParser::new();
        let tree = parser.parse(source).unwrap();
        let root = tree.root_node();

        fn dump(node: tree_sitter::Node, source: &str, depth: usize, file: &mut Vec<String>) {
            let indent = "  ".repeat(depth);
            let text = node.utf8_text(source.as_bytes()).unwrap_or("");
            let txt = if text.len() > 60 { format!("{}...", &text[..60]) } else { text.to_string() };
            file.push(format!("{}{:?} [{}:{}] \"{}\"",
                indent, node.kind(),
                node.start_position().row, node.start_position().column,
                txt));
            for i in 0..node.child_count() {
                if let Some(child) = node.child(i) {
                    dump(child, source, depth + 1, file);
                }
            }
        }

        let mut lines = Vec::new();
        dump(root, source, 0, &mut lines);
        println!("=== AST DUMP ===");
        for line in &lines { println!("{}", line); }

        // Check for import_statement
        let has_import = lines.iter().any(|l| l.contains("import_statement"));
        println!("has import_statement: {}", has_import);
    }

