    /// 调试测试：测试 import 查询匹配
    #[test]
    fn debug_import_query() {
        use streaming_iterator::StreamingIterator;
        use tree_sitter::{Query, QueryCursor};
        let source = r#"import { AuthService } from "./auth";"#;
        let parser = JavaScriptParser::new();
        let tree = parser.parse(source).unwrap();

        // 测试：不指定 field name，匹配 import_statement 子树中包含的所有 string_fragment
        let query_str = r#"
(import_statement
  (string (string_fragment) @import.path)
)
"#;
        let query = Query::new(&parser.language, query_str).unwrap();
        let mut cursor = QueryCursor::new();
        let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());
        let mut count = 0;
        while let Some(m) = matches.next() {
            count += 1;
            println!("Match {}:", count);
            for cap in m.captures {
                let name = query.capture_names()[cap.index as usize];
                let text = cap.node.utf8_text(source.as_bytes()).unwrap_or("");
                println!("  [{}] = \"{}\"", name, text);
            }
        }
        println!("Total query matches: {}", count);
    }

